1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (with fee) ---
15	  it("single sword (no modifiers, first contract) → premium 115 G (100 base + 10 first ins + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 115 });
21	  });
22	  it("single amulet (no modifiers, first contract) → premium 71 G (60 + 6 + 5)", () => {
23	    const result = processScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 71 });
28	  });
29	  it("single staff (no modifiers, first contract) → premium 93 G (80 + 8 + 5)", () => {
30	    const result = processScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result.results[0]).toEqual({ premium: 93 });
35	  });
36	  it("single potion (no modifiers, first contract) → premium 49 G (40 + 4 + 5)", () => {
37	    const result = processScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result.results[0]).toEqual({ premium: 49 });
42	  });
43	
44	  // --- Components base premiums ---
45	  it.todo("2 runes → base 50 G");
46	  it.todo("3 runes (block) → base 60 G");
47	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
48	  it.todo("7 runes → base 175 G");
49	
50	  // --- Alike components ---
51	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
52	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
53	
54	  // --- Item-specific modifiers ---
55	  it.todo("cursed sword (first contract) → cursed surcharge 50% applies");
56	  it.todo("sword enchantment 5 (first contract) → high-enchantment surcharge 30% applies");
57	  it.todo("sword enchantment 4 (first contract) → no high-enchantment surcharge");
58	  it.todo("cursed sword enchantment 5 → both surcharges apply");
59	
60	  // --- Policy-wide modifiers ---
61	  it.todo("customer 2 years → loyalty discount applies");
62	  it.todo("customer 1 year → no loyalty discount");
63	  it.todo("second contract → follow-up discount 15% applies");
64	
65	  // --- Modifier scope (item vs policy) ---
66	  it.todo("cursed sword + plain amulet → cursed surcharge applies to sword only; policy base 160, after curse 210 before fee");
67	
68	  // --- Rounding ---
69	  it.todo("premium yielding 197.5 G → rounded UP to 198 G");
70	
71	  // --- Integration examples ---
72	  it.todo("newcomer with cursed sword → premium 165 G");
73	  it.todo("long-standing customer's second contract with cursed enchanted sword → premium 160 G");
74	
75	  // --- Claim: standard reimbursement ---
76	  it.todo("steel sword enchantment 3, damage 500 G → payout 400 G (500 - 100 deductible)");
77	  it.todo("damage to rune (insurance 250 G), damage 200 G → payout 100 G");
78	
79	  // --- Claim: enchantment threshold ---
80	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
81	
82	  // --- Claim: dragon material ---
83	  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
84	
85	  // --- Claim: dragon + enchantment ---
86	  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
87	  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G");
88	
89	  // --- Deductible per damage event ---
90	  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (deductible per item)");
91	
92	  // --- Payout rounding ---
93	  it.todo("payout calc yielding 350.5 G → rounded DOWN to 350 G");
94	
95	  // --- Multiple items of same type ---
96	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
97	  it.todo("two swords damaged separately → each entry has own deductible");
98	  it.todo("damages array has more entries of a type than policy covers → CLI rejects (non-zero exit)");
99	
100	  // --- Cap exhaustion ---
101	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
102	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
103	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
104	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remainingCap 600");
105	  it.todo("sword (cap 2000), second claim 1500 after 1500 → payout 600, remainingCap 0");
106	
107	  // --- Edge cases ---
108	  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
109	  it.todo("claim references item not in policy → CLI exits non-zero");
110	  it.todo("claim with negative damage amount → CLI exits non-zero");
111	});
